// services/scheduler.ts
var TICK_CRON = "* * * * *";
var CLEANUP_CRON = "0 1 * * *";
var fetchCronJob = null;
var cleanupCronJob = null;
async function startScheduler() {
  await fetchDueFeeds("startup");
  fetchCronJob = Bun.cron(TICK_CRON, async () => {
    try {
      await fetchDueFeeds("cron");
    } catch (error52) {
      console.error("[fetch:cron]", error52);
    }
  });
  cleanupCronJob = Bun.cron(CLEANUP_CRON, async () => {
    try {
      clearItems();
      console.log("[cleanup:cron] Removed items older than 90 days");
    } catch (error52) {
      console.error("[cleanup:cron]", error52);
    }
  });
  console.log(`Fetch feeds scheduler: Bun.cron (cron ${TICK_CRON} UTC, per-feed 5\u201330 min)`);
  console.log(`Cleanup items scheduler: Bun.cron (cron ${CLEANUP_CRON} UTC, items older than 90 days)`);
}
async function stopScheduler() {
  if (fetchCronJob) {
    fetchCronJob.stop();
    fetchCronJob = null;
  }
  if (cleanupCronJob) {
    cleanupCronJob.stop();
    cleanupCronJob = null;
  }
}

// main.ts
var PUBLIC_DIR = join2(import.meta.dir, "public");
var indexHtml = () => Bun.file(join2(PUBLIC_DIR, "index.html"));
var serviceWorker = () => Bun.file(join2(PUBLIC_DIR, "sw.js"));
function manifestLocale(query2) {
  const v = query2.locale ?? query2.lang;
  if (v === "en" || v === "zh")
    return v;
  return "zh";
}
loadSettings();
startScheduler();
var host = resolveHost();
var restrictLocalhost = isLocalhostRestricted(host);
var backendRoutes = new Elysia().use(routes).use(routes2).use(routes3).use(routes4).use(routes5);
var protectedBackendRoutes = restrictLocalhost ? new Elysia().use(localhostOnly).use(backendRoutes) : backendRoutes;
var publicRoutes = new Elysia().get("/", indexHtml).get("/feeds", indexHtml).get("/settings", indexHtml).get("/manifest.webmanifest", ({ query: query2, set: set2 }) => {
  set2.headers["content-type"] = "application/manifest+json; charset=utf-8";
  return JSON.stringify(buildWebManifest(manifestLocale(query2)));
}).get("/sw.js", serviceWorker).get("/icons/*", ({ params }) => Bun.file(join2(PUBLIC_DIR, "icons", params["*"]))).get("/assets/*", ({ params }) => Bun.file(join2(PUBLIC_DIR, "assets", params["*"]))).use(protectedBackendRoutes);
var app = new Elysia().use(publicRoutes);
var port = resolvePort();
app.listen({ port, hostname: host });
if (restrictLocalhost) {
  console.log(`Listening on http://localhost:${app.server?.port} (API/SSE/MCP: localhost only)`);
} else {
  console.log(`Listening on http://${host}:${app.server?.port}/`);
}
var shuttingDown = false;
async function shutdown(signal) {
  if (shuttingDown) {
    process.exit(1);
    return;
  }
  shuttingDown = true;
  console.log(`
${signal} received, shutting down...`);
  await stopScheduler();
  await app.stop();
  closeDatabase();
  process.exit(0);
}
for (const signal of ["SIGINT", "SIGTERM"]) {
  process.on(signal, () => {
    shutdown(signal);
  });
}
